/*
 * IoT Sensor Data Collection System
 * Demonstrates: Data collection, circular buffer, basic analytics
 * Suitable for embedded/edge devices
 */

#include <stdio.h>
#include <stdlib.h>
#include <string.h>
#include <stdbool.h>
#include <time.h>
#include <math.h>

// Constants
#define MAX_DEVICES 10
#define BUFFER_SIZE 100
#define MAX_READINGS 1000

// Sensor reading structure
typedef struct {
 int device_id;
 char sensor_type[20];
 float value;
 char timestamp[30];
 char location[20];
} SensorReading;

// Circular buffer for streaming data
typedef struct {
 SensorReading readings[BUFFER_SIZE];
 int head;
 int tail;
 int count;
} CircularBuffer;

// Device statistics
typedef struct {
 int device_id;
 float min_value;
 float max_value;
 float sum;
 int reading_count;
 float readings[MAX_READINGS];
} DeviceStats;

// Initialize circular buffer
void init_buffer(CircularBuffer *buf) {
 buf->head = 0;
 buf->tail = 0;
 buf->count = 0;
}

// Add reading to buffer
bool add_to_buffer(CircularBuffer *buf, SensorReading *reading) {
 if (buf->count >= BUFFER_SIZE) {
 // Buffer full, overwrite oldest
 buf->tail = (buf->tail + 1) % BUFFER_SIZE;
 buf->count--;
 }

 buf->readings[buf->head] = *reading;
 buf->head = (buf->head + 1) % BUFFER_SIZE;
 buf->count++;

 return true;
}

// Get current timestamp
void get_timestamp(char *buffer) {
 time_t now = time(NULL);
 struct tm *tm_info = localtime(&now);
 strftime(buffer, 30, "%Y-%m-%d %H:%M:%S", tm_info);
}

// Simulate sensor reading generation
SensorReading generate_reading(int device_id, char *sensor_type) {
 SensorReading reading;
 reading.device_id = device_id;
 strcpy(reading.sensor_type, sensor_type);

 // Generate realistic sensor values with some randomness
 float base_value, variation;

 if (strcmp(sensor_type, "temperature") == 0) {
 base_value = 70.0;
 variation = 15.0;
 } else if (strcmp(sensor_type, "pressure") == 0) {
 base_value = 180.0;
 variation = 30.0;
 } else if (strcmp(sensor_type, "humidity") == 0) {
 base_value = 50.0;
 variation = 20.0;
 } else {
 base_value = 50.0;
 variation = 10.0;
 }

 // Add random variation
 reading.value = base_value + (((float)rand() / RAND_MAX) * variation * 2 - variation);

 get_timestamp(reading.timestamp);
 sprintf(reading.location, "Zone_%d", (device_id % 3) + 1);

 return reading;
}

// Calculate statistics for a device
void calculate_stats(DeviceStats *stats, float value) {
 if (stats->reading_count == 0 || value < stats->min_value) {
 stats->min_value = value;
 }
 if (stats->reading_count == 0 || value > stats->max_value) {
 stats->max_value = value;
 }

 stats->sum += value;

 // Store reading for advanced analytics (max 1000)
 if (stats->reading_count < MAX_READINGS) {
 stats->readings[stats->reading_count] = value;
 }
 stats->reading_count++;
}

// Calculate moving average
float calculate_moving_average(DeviceStats *stats, int window) {
 if (stats->reading_count < window) {
 window = stats->reading_count;
 }

 float sum = 0;
 int start = stats->reading_count - window;
 for (int i = start; i < stats->reading_count; i++) {
 sum += stats->readings[i];
 }

 return sum / window;
}

// Detect anomaly using simple threshold
bool detect_anomaly(float value, float threshold) {
 return value > threshold;
}

// Calculate standard deviation
float calculate_std_dev(DeviceStats *stats) {
 if (stats->reading_count < 2) {
 return 0.0;
 }

 float mean = stats->sum / stats->reading_count;
 float sum_squared_diff = 0;

 for (int i = 0; i < stats->reading_count; i++) {
 float diff = stats->readings[i] - mean;
 sum_squared_diff += diff * diff;
 }

 return sqrt(sum_squared_diff / (stats->reading_count - 1));
}

// Print sensor reading
void print_reading(SensorReading *r) {
 printf("[%s] Device: %d | Type: %-12s | Value: %7.2f | Location: %s\n",
 r->timestamp, r->device_id, r->sensor_type, r->value, r->location);
}

// Print statistics summary
void print_statistics(DeviceStats *stats) {
 printf("\n=== Device %d Statistics ===\n", stats->device_id);
 printf("Total Readings: %d\n", stats->reading_count);
 printf("Min Value: %.2f\n", stats->min_value);
 printf("Max Value: %.2f\n", stats->max_value);
 printf("Average: %.2f\n", stats->sum / (stats->reading_count > 0 ? stats->reading_count : 1));
 printf("Std Deviation: %.2f\n", calculate_std_dev(stats));
 printf("Moving Avg (10): %.2f\n", calculate_moving_average(stats, 10));
}

// Main demonstration
int main() {
 printf("========================================\n");
 printf(" IoT Sensor Data Collection System \n");
 printf("========================================\n\n");

 // Initialize random seed
 srand(time(NULL));

 // Initialize data structures
 CircularBuffer buffer;
 init_buffer(&buffer);

 DeviceStats device_stats[MAX_DEVICES];
 for (int i = 0; i < MAX_DEVICES; i++) {
 device_stats[i].device_id = i + 1;
 device_stats[i].min_value = 0;
 device_stats[i].max_value = 0;
 device_stats[i].sum = 0;
 device_stats[i].reading_count = 0;
 }

 // Thresholds for anomaly detection
 float thresholds[] = {85.0, 200.0, 90.0}; // temperature, pressure, humidity

 // Simulate data collection
 printf("--- Simulating IoT Data Collection ---\n\n");

 int num_readings = 30;
 for (int i = 0; i < num_readings; i++) {
 // Generate readings from multiple sensors
 SensorReading temp_reading = generate_reading(1, "temperature");
 SensorReading pressure_reading = generate_reading(2, "pressure");

 // Add to buffer
 add_to_buffer(&buffer, &temp_reading);
 add_to_buffer(&buffer, &pressure_reading);

 // Update statistics
 calculate_stats(&device_stats[0], temp_reading.value);
 calculate_stats(&device_stats[1], pressure_reading.value);

 // Check for anomalies
 if (detect_anomaly(temp_reading.value, thresholds[0])) {
 printf(" ⚠️ ALERT: Temperature anomaly detected! Value: %.2f (Threshold: %.0f)\n",
 temp_reading.value, thresholds[0]);
 }

 // Print every 10th reading
 if (i % 10 == 0) {
 printf("Reading #%d:\n", i + 1);
 print_reading(&temp_reading);
 print_reading(&pressure_reading);
 printf("\n");
 }
 }

 // Print accumulated statistics
 printf("\n========================================\n");
 printf(" ANALYTICS RESULTS \n");
 printf("========================================\n");

 print_statistics(&device_stats[0]); // Temperature device
 print_statistics(&device_stats[1]); // Pressure device

 // Summary
 printf("\n--- Summary ---\n");
 printf("Total readings in buffer: %d\n", buffer.count);
 printf("Buffer capacity: %d\n", BUFFER_SIZE);
 printf("Active devices: 2\n");

 printf("\n✅ IoT Data Collection Complete!\n");

 return 0;
}
